mapper.select:
SELECT m.id, m.session_id, m.role, m.content, m.tokens, m.metadata::TEXT AS metadata, m.created_at
FROM messages m
JOIN sessions s ON s.id = m.session_id
WHERE s.user_id = #{userId}
  AND s.id = #{sessionId}
ORDER BY m.created_at DESC, m.id DESC
LIMIT #{limit}

SELECT m.id, m.session_id, m.role, m.content, m.tokens, m.metadata::TEXT AS metadata, m.created_at
FROM messages m
JOIN sessions s ON s.id = m.session_id
WHERE s.user_id = #{userId}
  AND s.id = #{sessionId}
  AND m.id > #{afterMessageId}
ORDER BY m.created_at, m.id

SELECT COUNT(*)
FROM messages m
JOIN sessions s ON s.id = m.session_id
WHERE s.user_id = #{userId}
  AND s.id = #{sessionId}

SELECT COALESCE(SUM(m.tokens), 0)
FROM messages m
JOIN sessions s ON s.id = m.session_id
WHERE s.user_id = #{userId}
  AND s.id = #{sessionId}
